        else:
            logger.info("Using Triton Attention backend on V1 engine.")
            return ("vllm.v1.attention.backends."
                    "triton_attn.TritonAttentionBackend")
    if selected_backend == _Backend.ROCM_FLASH:
        if not cls.has_device_capability(90):
